QUALITY_THRESHOLD = 0.75
MIN_OUTPUT_LENGTH = 20    # characters — avoid trivially short ideal outputs
MAX_OUTPUT_LENGTH = 8000  # avoid bloated examples that waste context


def passes_quality_filter(rec: DataRecord) -> bool:
    if rec.quality_score < QUALITY_THRESHOLD:
        return False
    if len(rec.ideal_output) < MIN_OUTPUT_LENGTH:
        return False
    if len(rec.ideal_output) > MAX_OUTPUT_LENGTH:
        return False
    # Reject if ideal output is nearly identical to rejected output (low edit ratio)
    if rec.rejected_output:
        from difflib import SequenceMatcher
        ratio = SequenceMatcher(None, rec.ideal_output, rec.rejected_output).ratio()
        if ratio > 0.90:   # less than 10% changed — not informative
            return False
    return True


def apply_quality_filter(records: list[DataRecord]) -> tuple[list[DataRecord], dict]:
    passed = [r for r in records if passes_quality_filter(r)]
    stats = {
        "input": len(records),
        "passed": len(passed),
        "dropped": len(records) - len(passed),
        "drop_rate": round(1 - len(passed) / max(len(records), 1), 3),
    }
    return passed, stats

from collections import defaultdict


def deduplicate_exact(records: list[DataRecord]) -> tuple[list[DataRecord], dict]:
    """Keep only the highest-quality record per unique prompt_hash."""
    by_hash: dict[str, DataRecord] = {}
    for rec in records:
        existing = by_hash.get(rec.prompt_hash)
        if existing is None or rec.quality_score > existing.quality_score:
            by_hash[rec.prompt_hash] = rec
    deduped = list(by_hash.values())
    stats = {
        "input": len(records),
        "unique": len(deduped),
        "duplicates_removed": len(records) - len(deduped),
    }
    return deduped, stats


def deduplicate_near_duplicate(
    records: list[DataRecord],
    similarity_threshold: float = 0.85,
) -> list[DataRecord]:
    """
    Remove near-duplicate prompts using character-level similarity.
    O(n^2) — only practical for < 2000 records. Use embedding clustering for more.
    """
    from difflib import SequenceMatcher
    kept: list[DataRecord] = []
    for rec in sorted(records, key=lambda r: -r.quality_score):
        is_dup = any(
            SequenceMatcher(
                None,
                rec.messages[-1]["content"],
                k.messages[-1]["content"],
            ).ratio() >= similarity_threshold
            for k in kept
        )
        if not is_dup:
            kept.append(rec)
    return kept

