MAX_DIMENSION_FRACTION = 0.35  # no single dimension > 35% of dataset


def balance_by_dimension(
    records: list[DataRecord],
    max_fraction: float = MAX_DIMENSION_FRACTION,
    total_target: int | None = None,
) -> tuple[list[DataRecord], dict]:
    """
    Downsample over-represented dimensions to max_fraction.
    Under-represented dimensions are kept in full.
    """
    if not records:
        return [], {}

    total = total_target or len(records)
    cap = int(total * max_fraction)

    by_dim: dict[str, list[DataRecord]] = defaultdict(list)
    for rec in sorted(records, key=lambda r: -r.quality_score):
        dim = rec.dimension or "general"
        by_dim[dim].append(rec)

    result = []
    distribution = {}
    for dim, items in by_dim.items():
        allowed = min(len(items), cap)
        result.extend(items[:allowed])
        distribution[dim] = {"total": len(items), "kept": allowed}

    # Shuffle to avoid ordering by dimension
    import random; random.shuffle(result)
    return result, distribution


def coverage_report(records: list[DataRecord]) -> dict:
    counts = Counter(r.dimension or "general" for r in records)
    total  = len(records)
    return {
        dim: {"count": n, "fraction": round(n / total, 3)}
        for dim, n in counts.most_common()
    }
